import{_ as a,o as t,c as o,a2 as i}from"./chunks/framework.ChXBHUFc.js";const g=JSON.parse('{"title":"IMU streaming — solved (main goal)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/imu-streaming.md","filePath":"guide/imu-streaming.md","lastUpdated":1782601617000}'),s={name:"guide/imu-streaming.md"};function r(n,e,c,l,d,m){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="imu-streaming-—-solved-main-goal" tabindex="-1">IMU streaming — solved (main goal) <a class="header-anchor" href="#imu-streaming-—-solved-main-goal" aria-label="Permalink to &quot;IMU streaming — solved (main goal)&quot;">​</a></h1><p>The Triki streams raw accelerometer + gyroscope over BLE once you send a multi-byte start command on RX. <strong>Verified live here.</strong></p><h2 id="start-the-stream" tabindex="-1">Start the stream <a class="header-anchor" href="#start-the-stream" aria-label="Permalink to &quot;Start the stream&quot;">​</a></h2><p>Write to RX <code>…0002</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>20 10 00 D0 07 68 00 03</span></span></code></pre></div><p>(<code>68 00</code> = 104 → ~104 Hz sample rate.)</p><h2 id="stream-format" tabindex="-1">Stream format <a class="header-anchor" href="#stream-format" aria-label="Permalink to &quot;Stream format&quot;">​</a></h2><p>The device then pushes 14-byte frames on TX <code>…0003</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>22 00 | gyroX gyroY gyroZ | accelX accelY accelZ</span></span></code></pre></div><p>Each axis is a signed int16, little-endian. Scales:</p><ul><li><strong>gyro / 131.0</strong> → deg/s</li><li><strong>accel / 2048.0</strong> → g</li></ul><p>Frames arrive in bursts at ~104 Hz.</p><h2 id="verification" tabindex="-1">Verification <a class="header-anchor" href="#verification" aria-label="Permalink to &quot;Verification&quot;">​</a></h2><p>Under shaking, gyro swings ±10000+, and the accel axis aligned with gravity reads ≈ +2048 (= 1 g) — decode confirmed, measured ~109 Hz. Reader: <code>tools/ble_imu_stream.py</code> (see <a href="./tooling">Tooling</a>).</p><p>This is sufficient to use the token as a <strong>motion controller</strong> — recover orientation via gyro + accel fusion (e.g. Madgwick AHRS).</p><blockquote><p>Note: the single-byte opcodes (<code>0x05</code> / <code>0x07</code> / <code>0x09</code> / …) are a separate diagnostic/management interface — raw IMU is NOT there; it only comes from the start-stream command above.</p></blockquote>',16)])])}const h=a(s,[["render",r]]);export{g as __pageData,h as default};
